// === Manutencao preditiva - processamento multi-linha ===
// Mantem o estado de cada linha, agrega entre linhas para os gauges
// e gera uma serie por linha para os graficos.

let dados = msg.payload;
const linha = (msg.topic || 'sensores/linha?').split('/').pop();

if (typeof dados === 'string') {
    try {
        dados = JSON.parse(dados);
    } catch (erro) {
        node.warn(`JSON invalido em ${msg.topic}: ${dados}`);
        return null;
    }
}
if (!dados || typeof dados !== 'object') {
    node.warn(`Payload inesperado em ${msg.topic}`);
    return null;
}

// --- Leitura independente por sensor ---
// Um sensor ausente/invalido nao descarta os demais: mantem o ultimo valor valido da linha.
const estados = context.get('estados') || {};
const leitura = estados[linha] ? Object.assign({}, estados[linha].valores) : {};

function lerSensor(chave, campo) {
    const valor = Number(dados[campo]);
    if (Number.isFinite(valor)) {
        leitura[chave] = valor;
    } else {
        node.warn(`Sensor '${campo}' ausente/invalido em ${msg.topic}`);
    }
}

lerSensor('temperatura', 'temperatura');
lerSensor('umidade', 'umidade');
lerSensor('radiacao', 'radiacao');
lerSensor('pressao', 'pressao');
lerSensor('vazao', 'vazao');
lerSensor('vibracao', 'acelerometro');

estados[linha] = { valores: leitura, timestamp: new Date().toISOString() };
context.set('estados', estados);

const linhas = Object.keys(estados);

// --- Agregacao entre linhas ---
// Temperatura e vibracao: PIOR caso (maximo), pois disparam manutencao.
// Demais: MEDIA, como valor representativo do parque.
function agregar(chave, modo) {
    const vals = linhas
        .map((l) => estados[l].valores[chave])
        .filter((v) => Number.isFinite(v));
    if (vals.length === 0) return null;
    if (modo === 'max') return Math.max.apply(null, vals);
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}

const tempMax = agregar('temperatura', 'max');
const vibMax = agregar('vibracao', 'max');

function gauge(valor) {
    return Number.isFinite(valor) ? { payload: Number(valor.toFixed(2)) } : null;
}

const gTemp = gauge(tempMax);
const gUmid = gauge(agregar('umidade', 'media'));
const gRad = gauge(agregar('radiacao', 'media'));
const gPres = gauge(agregar('pressao', 'media'));
const gVazao = gauge(agregar('vazao', 'media'));
const gVib = gauge(vibMax);

// --- Graficos: uma serie por linha (topic = linha) ---
function chart(chave) {
    const v = leitura[chave];
    return Number.isFinite(v) ? { topic: linha, payload: v } : null;
}

const cTemp = chart('temperatura');
const cVib = chart('vibracao');
const cVazao = chart('vazao');

// --- Avaliacao de alerta sobre TODAS as linhas ---
const linhasAlerta = [];
for (const l of linhas) {
    const v = estados[l].valores;
    const motivos = [];
    if (Number.isFinite(v.temperatura) && v.temperatura > 35) {
        motivos.push(`temperatura ${v.temperatura.toFixed(1)} °C`);
    }
    if (Number.isFinite(v.vibracao) && v.vibracao > 4) {
        motivos.push(`vibração ${v.vibracao.toFixed(2)} g`);
    }
    if (motivos.length > 0) {
        linhasAlerta.push({ linha: l, motivos });
    }
}

const emAlerta = linhasAlerta.length > 0;
let texto;
let cor;
if (emAlerta) {
    cor = 'red';
    texto = 'ALERTA DE MANUTENÇÃO | ' +
        linhasAlerta.map((a) => `${a.linha}: ${a.motivos.join(' e ')}`).join('  ||  ');
} else {
    cor = 'green';
    const tMax = Number.isFinite(tempMax) ? tempMax.toFixed(1) : '--';
    const vMax = Number.isFinite(vibMax) ? vibMax.toFixed(2) : '--';
    texto = `NORMAL | ${linhas.length} linha(s) | Temp. máx ${tMax} °C | Vib. máx ${vMax} g`;
}

const alertaMsg = { topic: emAlerta ? 'ALERTA' : 'NORMAL', payload: texto, color: cor };

// --- Toast apenas na transicao normal -> alerta, por linha ---
const alertaPorLinha = context.get('alertaPorLinha') || {};
const estaEmAlerta = linhasAlerta.some((a) => a.linha === linha);
const estavaEmAlerta = alertaPorLinha[linha] || false;
let toastMsg = null;
if (estaEmAlerta && !estavaEmAlerta) {
    const info = linhasAlerta.find((a) => a.linha === linha);
    toastMsg = { topic: 'Manutenção preditiva', payload: `${linha}: ${info.motivos.join(' e ')}` };
}
alertaPorLinha[linha] = estaEmAlerta;
context.set('alertaPorLinha', alertaPorLinha);

return [gTemp, gUmid, gRad, gPres, gVazao, gVib, cTemp, cVib, cVazao, alertaMsg, toastMsg];
